"""
Parser class for THE THIN AIR game
"""

from typing import List, Tuple

class Parser:
    def __init__(self, game_state):
        self.game_state = game_state

        # Command aliases
        self.aliases = {
            "n": "north",
            "s": "south",
            "e": "east",
            "w": "west",
            "u": "up",
            "d": "down",
            "i": "inventory",
            "x": "examine",
            "get": "take",
            "use": "take",
            "put on": "wear",
            "remove": "take",
            "read": "examine",
            "repair": "install",
            "install": "install",
            "send": "transmit",
            "transmit": "transmit"
        }

        # Common filler words to remove
        self.filler_words = ["the", "at", "to", "on", "with", "using"]

    def parse_command(self, command: str) -> str:
        # Normalize command
        command = command.strip().lower()

        # Remove filler words
        for word in self.filler_words:
            command = command.replace(f" {word} ", " ")
            if command.startswith(f"{word} "):
                command = command[len(word) + 1:]
            if command.endswith(f" {word}"):
                command = command[:-len(word) - 1]

        # Handle empty command
        if not command:
            return "What?"

        # Split into verb and noun
        parts = command.split(" ", 1)
        verb = parts[0]
        noun = parts[1] if len(parts) > 1 else ""

        # Apply aliases
        if verb in self.aliases:
            verb = self.aliases[verb]

        # Process command based on verb
        if verb in ["north", "south", "east", "west", "up", "down", "in", "out"]:
            return self.move(verb)
        elif verb == "look" or verb == "examine":
            return self.examine(noun)
        elif verb == "take" or verb == "get":
            return self.take(noun)
        elif verb == "inventory" or verb == "i":
            return self.inventory()
        elif verb == "wear" or verb == "put on":
            return self.wear(noun)
        elif verb == "remove":
            return self.remove_item(noun)
        elif verb == "scan":
            return self.scan()
        elif verb == "help":
            return self.help()
        elif verb == "map":
            return self.map()
        elif verb == "read":
            return self.read(noun)
        elif verb == "install" or verb == "repair" or verb == "transmit":
            return self.install_or_repair(verb, noun)
        elif verb == "hide":
            return self.hide(noun)
        elif verb == "crawl":
            return self.crawl(noun)
        elif verb == "run":
            return self.run(noun)
        elif verb == "throw":
            return self.throw(noun)
        elif verb == "wait":
            return self.wait()
        elif verb == "quit" or verb == "exit":
            return self.quit_game()
        else:
            return f"I don't know how to {verb}."

    def move(self, direction: str) -> str:
        current_room = self.game_state.rooms[self.game_state.current_room_id]

        if direction in current_room.exits:
            new_room_id = current_room.exits[direction]
            self.game_state.current_room_id = new_room_id
            self.game_state.turn_count += 1

            # Check for toxic atmosphere
            if not self.game_state.player.suit_worn and new_room_id in ["surface", "landing_gear", "ridge", "cave_mouth", "signal_cave", "black_pool"]:
                self.game_state.player.outside_exposure_turns += 1
                if self.game_state.player.outside_exposure_turns >= 2:
                    return self.death_toxic_air()
                else:
                    return "You are not wearing a suit."

            return f"Moved {direction}."
        else:
            return f"No exit {direction}."

    def examine(self, noun: str) -> str:
        if not noun:
            # Examine current room
            room = self.game_state.rooms[self.game_state.current_room_id]
            return room.description

        # Check if item is in room
        room = self.game_state.rooms[self.game_state.current_room_id]
        item = room.get_item(noun)
        if item:
            return item.description

        # Check inventory
        for inv_item in self.game_state.player.inventory:
            if inv_item.matches_name(noun):
                return inv_item.description

        return f"You see no {noun} here."

    def take(self, noun: str) -> str:
        if not noun:
            return "Take what?"

        room = self.game_state.rooms[self.game_state.current_room_id]
        item = room.get_item(noun)

        if item and item.portable:
            room.remove_item(item)
            self.game_state.player.add_to_inventory(item)

            # Special handling for suit
            if item.name.lower() == "eva suit":
                self.game_state.player.suit_taken = True

            return f"Taken."
        elif item:
            return f"You can't take the {item.name}."
        else:
            return f"You see no {noun} here."

    def inventory(self) -> str:
        if not self.game_state.player.inventory:
            return "You carry nothing."

        items = [item.name for item in self.game_state.player.inventory]
        return f"You carry: {', '.join(items)}"

    def wear(self, noun: str) -> str:
        if not noun:
            return "Wear what?"

        # Check inventory
        for item in self.game_state.player.inventory:
            if item.matches_name(noun):
                if item.wearable:
                    self.game_state.player.wear_item(item)
                    self.game_state.player.set_suit_worn(True)
                    return f"You put on the {item.name}."
                else:
                    return f"You can't wear the {item.name}."

        # Check if item is in room
        room = self.game_state.rooms[self.game_state.current_room_id]
        item = room.get_item(noun)
        if item and item.wearable:
            room.remove_item(item)
            self.game_state.player.wear_item(item)
            self.game_state.player.set_suit_worn(True)
            return f"You put on the {item.name}."

        return f"You can't wear the {noun}."

    def remove_item(self, noun: str) -> str:
        if not noun:
            return "Remove what?"

        # Check worn items
        for item in self.game_state.player.worn_items:
            if item.matches_name(noun):
                self.game_state.player.remove_item(item)
                self.game_state.player.set_suit_worn(False)
                return f"You remove the {item.name}."

        return f"You're not wearing the {noun}."

    def scan(self) -> str:
        # For now, just return a basic scan result
        if not self.game_state.player.has_terminal:
            return "You don't have a scanner."

        if self.game_state.monster.phase == "dormant":
            return "No internal motion detected."
        elif self.game_state.monster.phase == "following":
            return "MOTION: outside\nDISTANCE: uncertain\nSIGNAL: intermittent"
        else:
            # Monster is aboard
            return "MOTION: west\nDISTANCE: 4 moves\nSIGNAL: intermittent"

    def help(self) -> str:
        return "Common commands:\n  north/south/east/west, in/out, up/down\n  look, examine <thing>, take <thing>\n  inventory, wear <thing>, use <thing>\n  scan, listen, hide, crawl <direction>\n  repair <thing>, read <thing>\n  map, help, quit"

    def map(self) -> str:
        return "Known rooms:\n- Cockpit\n- Central Corridor\n- Airlock\n- Surface"

    def read(self, noun: str) -> str:
        if not noun:
            return "Read what?"

        # Check inventory
        for item in self.game_state.player.inventory:
            if item.matches_name(noun):
                if item.readable_text:
                    return item.readable_text
                else:
                    return f"You can't read the {item.name}."

        # Check room items
        room = self.game_state.rooms[self.game_state.current_room_id]
        item = room.get_item(noun)
        if item and item.readable_text:
            return item.readable_text

        return f"You can't read the {noun}."

    def install_or_repair(self, verb: str, noun: str) -> str:
        if not noun:
            return "Install what?"

        # Check if we're in communications room
        if self.game_state.current_room_id != "communications":
            return "You can only repair the transmitter here."

        # Check if we have all required parts
        if (self.game_state.flags["has_power_coupler"] and 
            self.game_state.flags["has_signal_relay"] and 
            self.game_state.flags["has_antenna_key"]):

            # Repair the transmitter
            self.game_state.flags["transmitter_repaired"] = True
            self.game_state.flags["warning_sent"] = True
            self.game_state.win_state = True
            return "TRANSMISSION READY.\nMessage?"
        else:
            missing_parts = []
            if not self.game_state.flags["has_power_coupler"]:
                missing_parts.append("power coupler")
            if not self.game_state.flags["has_signal_relay"]:
                missing_parts.append("signal relay")
            if not self.game_state.flags["has_antenna_key"]:
                missing_parts.append("antenna key")

            return f"Missing: {', '.join(missing_parts)}"

    def hide(self, noun: str) -> str:
        return "You hide in the shadows."

    def crawl(self, direction: str) -> str:
        return "You crawl."

    def run(self, direction: str) -> str:
        return "You run."

    def throw(self, noun: str) -> str:
        return "You throw something."

    def wait(self) -> str:
        return "You wait."

    def quit_game(self) -> str:
        return "Goodbye!"

    def death_toxic_air(self) -> str:
        self.game_state.death_state = "toxic_air"
        return "You make it four steps.\nThat is all."
